def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(pos1, pos2):
        return np.sqrt(np.sum((pos1 - pos2) ** 2))

    def time_to_node(start_pos, end_pos, speed):
        distance = euclidean_distance(start_pos, end_pos)
        return distance / speed

    def cluster_density(target_pos, threshold=5):
        # Calculate the number of nodes within certain distance threshold
        return sum(1 for pos in unvisited_customers if euclidean_distance(target_pos, pos) < threshold)

    def score_node(node_pos, idx):
        arrival_time = current_time + time_to_node(cur_truck_pos, node_pos, truck_speed)
        window_start, window_end = time_windows[idx]
        density = cluster_density(node_pos)

        if arrival_time < window_start:
            # Calculate waiting time as penalty, but improve score with high density
            wait_time = window_start - arrival_time
            score = (wait_time * 0.5) - (density * 0.5) 
        elif arrival_time > window_end:
            # Penalty for missing time window offset by nearby nodes
            missed_time = arrival_time - window_end
            score = (missed_time * 1.2) + (density * 0.3)
        else:
            # No wait and no penalty, bonus for high density
            score = density * -0.7

        return score + arrival_time - current_time 

    best_score = float('inf')
    best_node = None

    for idx, customer_pos in enumerate(unvisited_customers):
        node_score = score_node(customer_pos, idx)
        if node_score < best_score:
            best_score = node_score
            best_node = idx

    return best_node
